          { label: '썸네일 생성수', value: '458', color: 'text-emerald-500' },
          { label: '활성 사용자', value: '12', color: 'text-orange-500' },
        ].map((stat, idx) => (
          <div key={idx} className="bg-zinc-900 border border-zinc-800 p-6 rounded-2xl shadow-xl">
