          </div>
        </div>
        <div className="mt-4 flex gap-3 w-full">
          <button onClick={handleExportButtonClick} className="flex-1 bg-purple-600 hover:bg-purple-700 text-white font-bold py-3 rounded-lg transition-all text-sm md:text-base">
            디자인 내보내기 (PNG)
